import React, { useState } from "react";
import {
  Button,
  Typography,
  Box,
  Grid,
  TextField,
  Card,
  CardContent,
  Alert,
} from "@mui/material";
import PhotoCamera from "@mui/icons-material/PhotoCamera";
import UploadFileIcon from "@mui/icons-material/UploadFile";
import { useNavigate } from "react-router-dom";
import { uploadRiderDocs } from "../services/api";

export default function DocumentUpload() {
  const navigate = useNavigate();

  const [form, setForm] = useState({
    licenseNumber: "",
    rcNumber: "",
    insuranceNumber: "",
    aadharFrontNumber: "",
    aadharBackNumber: "",
    licenseImage: null,
    rcImage: null,
    insuranceImage: null,
    aadharFront: null,
    aadharBack: null,
  });

  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  // Handle text input
  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  // Handle file input
  const handleFile = (field, file) => {
  if (file instanceof File) {   // ✅ only accept real File objects
    setForm({ ...form, [field]: file });
  }
};


  // Validation
  const validateForm = () => {
    const requiredFields = [
      "licenseNumber",
      "rcNumber",
      "insuranceNumber",
      "aadharFrontNumber",
      "aadharBackNumber",
      "licenseImage",
      "rcImage",
      "insuranceImage",
      "aadharFront",
      "aadharBack",
    ];

    for (let field of requiredFields) {
      if (!form[field]) {
        return `Please provide ${field.replace(/([A-Z])/g, " $1")}`;
      }
    }
    return null;
  };

  // Submit
  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setSuccess("");

    const validationError = validateForm();
    if (validationError) {
      setError(validationError);
      return;
    }

    try {
      const token = localStorage.getItem("token");
      if (!token) {
        setError("You must be logged in to submit documents.");
        return;
      }

      // ✅ Prepare FormData (text + files)
      const data = new FormData();
      Object.keys(form).forEach((key) => {
        if (form[key] !== null) {
        data.append(key, form[key]);
        }
      });

      await uploadRiderDocs(token, data);

      setSuccess("Documents submitted successfully! Verification in progress.");

      // ✅ Navigate to Rider Dashboard
      navigate("/rider-dashboard", {
        state: { message: "Verification in progress" },
      });
    } catch (err) {
      console.error("❌ Upload error:", err.response?.data || err.message);
      setError(err.response?.data?.message || "Error uploading documents");
    }
  };

  // Reusable Document Row
  const DocumentRow = ({ label, name, fileField }) => (
    <Card sx={{ mb: 3, borderRadius: 2, boxShadow: 2 }}>
      <CardContent>
        <Grid container spacing={2} alignItems="center">
          {/* Left: Number Field */}
          <Grid item xs={12} md={6}>
            <TextField
              fullWidth
              label={`${label} Number`}
              name={name}
              value={form[name]}
              onChange={handleChange}
            />
          </Grid>

          {/* Right: Upload + Camera */}
          <Grid item xs={12} md={6}>
            <Typography variant="subtitle2" sx={{ mb: 1 }}>
              {label} Image
            </Typography>
            <Box sx={{ display: "flex", gap: 2, alignItems: "center" }}>
              <Button
                component="label"
                variant="outlined"
                startIcon={<UploadFileIcon />}
              >
                Upload
                <input
                  type="file"
                  hidden
                  accept="image/*"
                  onChange={(e) => handleFile(fileField, e.target.files[0])}
                />
              </Button>
              <Button
                variant="contained"
                color="secondary"
                startIcon={<PhotoCamera />}
                component="label"
              >
                Camera
                <input
                  type="file"
                  hidden
                  accept="image/*"
                  capture="environment"
                  onChange={(e) => handleFile(fileField, e.target.files[0])}
                />
              </Button>
            </Box>
            {form[fileField] && (
              <Typography variant="body2" sx={{ mt: 1, color: "green" }}>
                📂 {form[fileField].name}
              </Typography>
            )}
          </Grid>
        </Grid>
      </CardContent>
    </Card>
  );

  return (
    <Box sx={{ p: 4 }}>
      <Typography
        variant="h4"
        sx={{ textAlign: "center", fontWeight: "bold", mb: 4 }}
      >
        Document Verification
      </Typography>

      {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
      {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

      <form onSubmit={handleSubmit}>
        <DocumentRow
          label="Driving License"
          name="licenseNumber"
          fileField="licenseImage"
        />
        <DocumentRow label="RC" name="rcNumber" fileField="rcImage" />
        <DocumentRow
          label="Insurance"
          name="insuranceNumber"
          fileField="insuranceImage"
        />
        <DocumentRow
          label="Aadhar (Front)"
          name="aadharFrontNumber"
          fileField="aadharFront"
        />
        <DocumentRow
          label="Aadhar (Back)"
          name="aadharBackNumber"
          fileField="aadharBack"
        />

        <Box sx={{ textAlign: "center", mt: 4 }}>
          <Button
            type="submit"
            variant="contained"
            sx={{
              bgcolor: "black",
              color: "white",
              px: 4,
              py: 1.2,
              fontWeight: "bold",
              borderRadius: 2,
              "&:hover": { bgcolor: "#333" },
            }}
          >
            Submit Documents
          </Button>
        </Box>
      </form>
    </Box>
  );
}
